# Fully generated by Gemini Pro

import json
import os
import warnings
from rouge_score import rouge_scorer
from bert_score import score as bert_score

# Suppress Hugging Face warnings for clean output
warnings.filterwarnings("ignore")

def calculate_json_metrics(file_path):
    """Calculates JSON validity, schema compliance, exact match, and Field-Level F1."""
    with open(file_path, "r", encoding="utf-8") as f:
        data = json.load(f)
        
    valid_json_count = 0
    schema_compliance_count = 0
    exact_match_count = 0
    f1_scores = []
    
    for item in data:
        generated = item.get("generated_output", "").strip()
        expected = item.get("expected_output", "").strip()
        
        # Strip markdown
        for prefix in ["```json", "```"]:
            if generated.startswith(prefix):
                generated = generated[len(prefix):]
        if generated.endswith("```"):
            generated = generated[:-3]
        generated = generated.strip()
        
        if generated == expected:
            exact_match_count += 1
            
        try:
            gen_obj = json.loads(generated)
            exp_obj = json.loads(expected)
            valid_json_count += 1
            
            if isinstance(gen_obj, dict) and isinstance(exp_obj, dict):
                if set(gen_obj.keys()) == set(exp_obj.keys()):
                    schema_compliance_count += 1
                    
                # Field-Level F1
                tp = sum(1 for k, v in gen_obj.items() if k in exp_obj and exp_obj[k] == v)
                fp = sum(1 for k in gen_obj.keys() if k not in exp_obj or exp_obj.get(k) != gen_obj[k])
                fn = sum(1 for k in exp_obj.keys() if k not in gen_obj)
                
                precision = tp / (tp + fp) if (tp + fp) > 0 else 0
                recall = tp / (tp + fn) if (tp + fn) > 0 else 0
                
                if precision + recall > 0:
                    f1_scores.append(2 * (precision * recall) / (precision + recall))
                else:
                    f1_scores.append(0)
            
        except Exception:
            f1_scores.append(0)
            
    total = len(data)
    validity_rate = (valid_json_count / total) * 100 if total > 0 else 0
    schema_rate = (schema_compliance_count / valid_json_count) * 100 if valid_json_count > 0 else 0
    exact_match_rate = (exact_match_count / total) * 100 if total > 0 else 0
    avg_f1 = (sum(f1_scores) / len(f1_scores)) * 100 if f1_scores else 0
    
    return validity_rate, schema_rate, exact_match_rate, avg_f1

def calculate_nlp_metrics(file_path):
    """Calculates Output Length, ROUGE (1, 2, L), and BERTScore."""
    with open(file_path, "r", encoding="utf-8") as f:
        data = json.load(f)
        
    scorer = rouge_scorer.RougeScorer(['rouge1', 'rouge2', 'rougeL'], use_stemmer=True)
    r1, r2, rl, lengths = [], [], [], []
    refs, hyps = [], []
    
    for item in data:
        expected = item.get("expected_output", "")
        generated = item.get("generated_output", "")
        
        # Token length approximation (splitting by space)
        lengths.append(len(generated.split()))
        
        # ROUGE
        scores = scorer.score(expected, generated)
        r1.append(scores['rouge1'].fmeasure)
        r2.append(scores['rouge2'].fmeasure)
        rl.append(scores['rougeL'].fmeasure)
        
        refs.append(expected)
        hyps.append(generated)
        
    avg_len = sum(lengths) / len(lengths) if lengths else 0
    avg_r1 = (sum(r1) / len(r1)) * 100
    avg_r2 = (sum(r2) / len(r2)) * 100
    avg_rl = (sum(rl) / len(rl)) * 100
    
    # BERTScore
    print(f"Calculating BERTScore for {os.path.basename(file_path)}...")
    P, R, F1 = bert_score(hyps, refs, lang="en", verbose=False)
    avg_bert = F1.mean().item() * 100
    
    return avg_len, avg_r1, avg_r2, avg_rl, avg_bert

def calculate_judge_win_rate(judge_file, target_winner_name):
    if not os.path.exists(judge_file):
        return "N/A"
    with open(judge_file, "r", encoding="utf-8") as f:
        data = json.load(f)
        
    wins = sum(1 for item in data if item.get("winner", "") == target_winner_name)
    return f"{(wins / len(data)) * 100:.1f}%" if len(data) > 0 else "0.0%"

def main():
    print("Aggregating Final Assignment Metrics (This will take a minute for BERTScore)...\n")
    
    # JSON Metrics
    cp0_val, cp0_sch, cp0_ex, cp0_f1 = calculate_json_metrics("data/eval/inference_results/cp0_json_results.json")
    cp1_val, cp1_sch, cp1_ex, cp1_f1 = calculate_json_metrics("data/eval/inference_results/cp1_json_results.json")
    cp2_val, cp2_sch, cp2_ex, cp2_f1 = calculate_json_metrics("data/eval/inference_results/cp2_json_results.json")
    
    # NLP Metrics
    cp0_len, cp0_r1, cp0_r2, cp0_rl, cp0_bert = calculate_nlp_metrics("data/eval/inference_results/cp0_alpaca_results.json")
    cp1_len, cp1_r1, cp1_r2, cp1_rl, cp1_bert = calculate_nlp_metrics("data/eval/inference_results/cp1_alpaca_results.json")
    cp2_len, cp2_r1, cp2_r2, cp2_rl, cp2_bert = calculate_nlp_metrics("data/eval/inference_results/cp2_alpaca_results.json")
    
    # Judge Win Rates
    cp1_vs_cp0 = calculate_judge_win_rate("logs/judge_cp0_vs_cp1.json", "B") 
    cp2_vs_cp1_alpaca = calculate_judge_win_rate("logs/judge_cp1_vs_cp2.json", "B")
    cp2_vs_cp1_json = calculate_judge_win_rate("logs/judge_cp1_vs_cp2_json.json", "B")
    
    print("\n### 4.1 & 4.2 Alpaca / General Tasks Comparison")
    print("| Checkpoint | Alpaca Judge Win Rate | R-1 | R-2 | ROUGE-L | BERTScore | Avg Length |")
    print("| :--- | :--- | :--- | :--- | :--- | :--- | :--- |")
    print(f"| CP0: Base | N/A (Baseline) | {cp0_r1:.1f} | {cp0_r2:.1f} | {cp0_rl:.1f} | {cp0_bert:.1f} | {cp0_len:.0f} words |")
    print(f"| CP1: Stage 1 | {cp1_vs_cp0} vs CP0 | {cp1_r1:.1f} | {cp1_r2:.1f} | {cp1_rl:.1f} | {cp1_bert:.1f} | {cp1_len:.0f} words |")
    print(f"| CP2: Stage 2 | {cp2_vs_cp1_alpaca} vs CP1 | {cp2_r1:.1f} | {cp2_r2:.1f} | {cp2_rl:.1f} | {cp2_bert:.1f} | {cp2_len:.0f} words |")
    
    print("\n### 4.3 JSON Structured Output Evaluation")
    print("| Checkpoint | JSON Judge Win Rate | JSON Validity | Schema Compliance | Exact Match | Field-Level F1 |")
    print("| :--- | :--- | :--- | :--- | :--- | :--- |")
    print(f"| CP0: Base | N/A (Baseline) | {cp0_val:.1f}% | {cp0_sch:.1f}% | {cp0_ex:.1f}% | {cp0_f1:.1f}% |")
    print(f"| CP1: Stage 1 | N/A | {cp1_val:.1f}% | {cp1_sch:.1f}% | {cp1_ex:.1f}% | {cp1_f1:.1f}% |")
    print(f"| CP2: Stage 2 | {cp2_vs_cp1_json} vs CP1 | {cp2_val:.1f}% | {cp2_sch:.1f}% | {cp2_ex:.1f}% | {cp2_f1:.1f}% |")

if __name__ == "__main__":
    main()